            if (!visited[i][j][newStep] || newTotalCost < visited[i][j][newStep]) {
                visited[i][j][newStep] = newTotalCost;
                heap.enqueue({ i, j, step: newStep, totalCost: newTotalCost });
            }
        }
    }

    return -1; // in case no path found (shouldn't happen per problem statement)
}
