```javascript
function solve(m, n, waitCost) {
    // Create a priority queue based on min-heap to store [totalCost, i, j, step]
    const heap = new MinPriorityQueue({
        priority: (item) => item[0]
    });

    // Initialize the distance matrix with Infinity
    const dist = new Array(m);
    for (let i = 0; i < m; i++) {
        dist[i] = new Array(n);
        for (let j =  ۰; j < n; j++) {
            dist[i][j] = new Map(); // step -> cost
        }
    }

    // Starting point: (0, 0) at step 1 with cost (0+1)*(0+1) = 1
    const startCost = 1;
    heap.enqueue([startCost, 0, 0, 1]);
    dist[0][0].set(1, startCost);

    const directions = [[1, 0], [0, 1]]; // down and right

    while (!heap.isEmpty()) {
        const { element: current } = heap.dequeue();
        const [currentCost, i, j, step] = current;

        if (i === m - 1 && j === n - 1) {
            return currentCost;
        }

        if (step % 2 === 1) {
            // Odd step: move to adjacent cells
            for (const [di, dj] of directions) {
                const ni = i + di;
                const nj = j + dj;
                if (ni < m && nj < n) {
                    const nextStep = step + 1;
                    const moveCost = (ni + 1) * (nj + 1);
                    const newCost = currentCost + moveCost;

                    if (!dist[ni][nj].has(nextStep) || newCost < dist[ni][nj].get(nextStep)) {
                        dist[ni][nj].set(nextStep, newCost);
                        heap.enqueue([newCost, ni, nj, nextStep]);
                    }
                }
            }
        } else {
            // Even step: wait in current cell
            const nextStep = step + 1;
            const waitCostHere = waitCost[i][j];
            const newCost = currentCost + waitCostHere;

            if (!dist[i][j].has(nextStep) || newCost < dist[i][j].get(nextStep)) {
                dist[i][j].set(nextStep, newCost);
                heap.enqueue([newCost, i, j, nextStep]);
            }
        }
    }

    return -1; // in case no path found (shouldn't happen as per problem statement)
}
